# eval/mutation_gates.py
from dataclasses import dataclass

@dataclass
class GateConfig:
    mutation_score: float      # % harness mutants killed
    robustness_score: float    # % prompt mutations that are non-fragile
    line_coverage: float       # % lines executed by any test
    frequency: str             # "pr" | "nightly"

GATES: dict[str, GateConfig] = {
    "safety": GateConfig(
        mutation_score=0.90,
        robustness_score=0.85,
        line_coverage=1.00,    # 100% — every safety code path must be tested
        frequency="pr",
    ),
    "quality": GateConfig(
        mutation_score=0.85,
        robustness_score=0.80,
        line_coverage=0.95,
        frequency="pr",
    ),
    "performance": GateConfig(
        mutation_score=0.75,
        robustness_score=0.75,
        line_coverage=0.90,
        frequency="nightly",
    ),
    "infrastructure": GateConfig(
        mutation_score=0.75,
        robustness_score=0.70,
        line_coverage=0.80,
        frequency="nightly",
    ),
}

def get_gate(feature_tag: str) -> GateConfig:
    return GATES.get(feature_tag, GATES["quality"])

def check_gates(
    feature_tag: str,
    mutation_score: float,
    robustness_score: float,
    line_coverage: float,
) -> list[str]:
    gate = get_gate(feature_tag)
    failures = []
    if mutation_score < gate.mutation_score:
        failures.append(
            f"Mutation score {mutation_score:.1%} below gate {gate.mutation_score:.1%}"
        )
    if robustness_score < gate.robustness_score:
        failures.append(
            f"Robustness score {robustness_score:.1%} below gate {gate.robustness_score:.1%}"
        )
    if line_coverage < gate.line_coverage:
        failures.append(
            f"Line coverage {line_coverage:.1%} below gate {gate.line_coverage:.1%}"
        )
    return failures

# eval/mutation_suppressions.py
import json, pathlib, datetime

SUPPRESSIONS_FILE = pathlib.Path("eval/mutation_suppressions.json")

def load_suppressions() -> list[dict]:
    if not SUPPRESSIONS_FILE.exists():
        return []
    return json.loads(SUPPRESSIONS_FILE.read_text())

def add_suppression(mutant_id: int, reason: str, author: str):
    sups = load_suppressions()
    # Check no duplicate
    if any(s["mutant_id"] == mutant_id for s in sups):
        print(f"Mutant {mutant_id} already suppressed")
        return
    sups.append({
        "mutant_id": mutant_id,
        "reason": reason,
        "author": author,
        "date": datetime.date.today().isoformat(),
        "expires": (datetime.date.today() + datetime.timedelta(days=90)).isoformat(),
    })
    SUPPRESSIONS_FILE.write_text(json.dumps(sups, indent=2))
    print(f"Suppressed mutant {mutant_id}: {reason}")

def check_expired():
    today = datetime.date.today().isoformat()
    sups = load_suppressions()
    expired = [s for s in sups if s.get("expires", "9999") < today]
    if expired:
        print(f"WARNING: {len(expired)} suppression(s) have expired:")
        for s in expired:
            print(f"  Mutant #{s['mutant_id']} (expired {s['expires']}): {s['reason']}")
        raise SystemExit("Expired suppressions must be reviewed before CI passes")
